      var dependencyY=0;groupDefs.slice(1).forEach(function(group){group.nodes.forEach(function(node,index){positions.set(node.id,{x:1160+(index%2)*220,y:dependencyY+Math.floor(index/2)*68});});dependencyY+=Math.max(160,Math.ceil(group.nodes.length/2)*68+90);});return;
